import{_ as i,c as o,o as r,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.33: GitLab Duo Support Added, Project Experience Improved","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.33.md","filePath":"en/changelog/v1.1.33.md","lastUpdated":1772014034000}'),l={name:"en/changelog/v1.1.33.md"};function n(s,a,d,h,p,c){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-33-gitlab-duo-support-added-project-experience-improved" tabindex="-1">v1.1.33: GitLab Duo Support Added, Project Experience Improved <a class="header-anchor" href="#v1-1-33-gitlab-duo-support-added-project-experience-improved" aria-label="Permalink to “v1.1.33: GitLab Duo Support Added, Project Experience Improved”">​</a></h1><p><strong>Release Date</strong>: January 23, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update adds thinking presets for Google Vertex Anthropic, supports GitLab Duo models, and improves the project adding and renaming experience.</p><hr><h2 id="new-feature-gitlab-duo-model-support" tabindex="-1">New Feature: GitLab Duo Model Support <a class="header-anchor" href="#new-feature-gitlab-duo-model-support" aria-label="Permalink to “New Feature: GitLab Duo Model Support”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>OpenCode now supports <strong>GitLab Duo</strong> models! GitLab Duo is an AI programming assistant based on OpenAI that provides code completion, code generation, and more within GitLab environments.</p><h3 id="what-is-gitlab-duo" tabindex="-1">What is GitLab Duo? <a class="header-anchor" href="#what-is-gitlab-duo" aria-label="Permalink to “What is GitLab Duo?”">​</a></h3><p>GitLab Duo is an AI-assisted programming service provided by GitLab that helps developers:</p><ul><li>Generate code</li><li>Explain code</li><li>Code review</li><li>Optimize code</li></ul><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3><ol><li>Open <strong>Settings</strong></li><li>Find <strong>Model</strong> settings</li><li>Select or configure GitLab Duo provider</li><li>Enter your API key</li><li>Start using!</li></ol><hr><h2 id="improvement-google-vertex-anthropic-thinking-presets" tabindex="-1">Improvement: Google Vertex Anthropic Thinking Presets <a class="header-anchor" href="#improvement-google-vertex-anthropic-thinking-presets" aria-label="Permalink to “Improvement: Google Vertex Anthropic Thinking Presets”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added <strong>thinking presets</strong> for Google Vertex&#39;s Anthropic provider.</p><h3 id="what-s-it-for" tabindex="-1">What&#39;s it for? <a class="header-anchor" href="#what-s-it-for" aria-label="Permalink to “What&#39;s it for?”">​</a></h3><p>Thinking presets allow Claude models to:</p><ul><li>&quot;Think&quot; before outputting on complex tasks</li><li>Better decompose problems and plan solutions</li><li>Improve code generation accuracy</li></ul><h3 id="how-to-enable" tabindex="-1">How to enable? <a class="header-anchor" href="#how-to-enable" aria-label="Permalink to “How to enable?”">​</a></h3><p>When using Google Vertex Anthropic models, thinking presets are applied automatically - no manual configuration needed.</p><hr><h2 id="improvement-project-adding-and-renaming" tabindex="-1">Improvement: Project Adding and Renaming <a class="header-anchor" href="#improvement-project-adding-and-renaming" aria-label="Permalink to “Improvement: Project Adding and Renaming”">​</a></h2><h3 id="previous-issues" tabindex="-1">Previous Issues <a class="header-anchor" href="#previous-issues" aria-label="Permalink to “Previous Issues”">​</a></h3><ul><li>Could only add projects from specific directory depths</li><li>Couldn&#39;t add projects from root directory</li><li>Non-git projects couldn&#39;t be renamed</li></ul><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Now you can:</p><ul><li>Add projects from folders at any directory depth</li><li>Add projects directly from root directory</li><li>Rename non-git repository projects</li><li>Project icon color flashing issue fixed</li></ul><h3 id="how-to-use-1" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to use?”">​</a></h3><p><strong>Add Project</strong>:</p><ol><li>Click <strong>Add Project</strong></li><li>Browse folders at any depth</li><li>Select the project to add</li></ol><p><strong>Rename Project</strong> (non-git projects only):</p><ol><li>Right-click the project in the project list</li><li>Select <strong>Rename</strong></li><li>Enter new name</li></ol><hr><h2 id="improvement-more-complete-folder-completion" tabindex="-1">Improvement: More Complete Folder Completion <a class="header-anchor" href="#improvement-more-complete-folder-completion" aria-label="Permalink to “Improvement: More Complete Folder Completion”">​</a></h2><h3 id="what-was-updated-2" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-2" aria-label="Permalink to “What was updated?”">​</a></h3><p>Fixed the issue where folder completion was missing the last part of the path.</p><h3 id="what-s-the-benefit" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>When entering paths, autocomplete will display complete folder names, making it easier to select target folders.</p><hr><h2 id="improvement-completion-priority-optimization" tabindex="-1">Improvement: Completion Priority Optimization <a class="header-anchor" href="#improvement-completion-priority-optimization" aria-label="Permalink to “Improvement: Completion Priority Optimization”">​</a></h2><h3 id="what-was-updated-3" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-3" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added weights to fuzzy search in TUI to maintain title priority.</p><h3 id="what-s-the-benefit-1" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-1" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>When searching, results matching titles will appear higher, helping you find what you need faster.</p><hr><h2 id="new-feature-show-file-path-in-permission-interface" tabindex="-1">New Feature: Show File Path in Permission Interface <a class="header-anchor" href="#new-feature-show-file-path-in-permission-interface" aria-label="Permalink to “New Feature: Show File Path in Permission Interface”">​</a></h2><h3 id="what-was-updated-4" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-4" aria-label="Permalink to “What was updated?”">​</a></h3><p>The permission interface for <code>apply_patch</code> requests now displays the file path.</p><h3 id="what-s-the-benefit-2" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-2" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>When AI requests file modifications, you can clearly see which file will be modified, allowing safer authorization.</p><hr><h2 id="new-feature-display-app-version" tabindex="-1">New Feature: Display App Version <a class="header-anchor" href="#new-feature-display-app-version" aria-label="Permalink to “New Feature: Display App Version”">​</a></h2><h3 id="what-was-updated-5" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-5" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added app version display to the settings interface.</p><h3 id="how-to-view" tabindex="-1">How to view? <a class="header-anchor" href="#how-to-view" aria-label="Permalink to “How to view?”">​</a></h3><ol><li>Open <strong>Settings</strong></li><li>Check the bottom of the interface or the about section</li><li>See the current OpenCode version number</li></ol><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using GitLab</td><td>✅ <strong>Recommended upgrade</strong> (Duo model support)</td></tr><tr><td>Using Google Vertex Anthropic</td><td>✅ Recommended upgrade (thinking presets)</td></tr><tr><td>Frequently add/manage projects</td><td>✅ Recommended upgrade (experience improvements)</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',63),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add thinking presets for Google Vertex Anthropic provider (@zerone0x)</li><li>Added support for OpenAI-based GitLab Duo models (@vglafirov)</li><li>Show file path in apply_patch request permission screen (@iltenahmet)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add weight to fuzzy search to maintain title priority in TUI (@IdrisGit)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Session shouldn&#39;t be keyed</li><li>Flash of fallback icon for projects fixed</li><li>Fix project icon color flash on load</li><li>Fixed folder suggestions missing last part in path completion</li><li>Allow adding projects from any directory depth</li><li>Allow adding projects from root directory in the app</li><li>Non-git projects can now be renamed</li><li>Add app version display to settings (@alexyaroshuk)</li></ul><p><strong>Thank you to 5 community contributors:</strong></p><ul><li>@iltenahmet: <ul><li>fix(ui): show file path in apply_patch request permission screen (#10079)</li></ul></li><li>@alexyaroshuk: <ul><li>feat(app): add app version display to settings (#10095)</li></ul></li><li>@IdrisGit: <ul><li>fix(tui): add weight to fuzzy search to maintain title priority (#10106)</li></ul></li><li>@vglafirov: <ul><li>feat(gitlab): Added support for OpenAI based GitLab Duo models (#10108)</li></ul></li><li>@zerone0x: <ul><li>fix(provider): add thinking presets for Google Vertex Anthropic (#9953)</li></ul></li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=i(l,[["render",n]]);export{m as __pageData,g as default};
